select.isEqual:
SELECT ( SELECT COUNT(*) FROM TBL_USERMASTER JOIN TBL_DEPTMASTER ON TBL_DEPTMASTER.CN = TBL_USERMASTER.DEPARTMENT AND TBL_DEPTMASTER.TENANT_ID = TBL_USERMASTER.TENANT_ID JOIN TBL_USER_JOBMASTER ON TBL_USERMASTER.EXTENSIONATTRIBUTE7 = TBL_USER_JOBMASTER.JOBID AND TBL_USERMASTER.PHYSICALDELIVERYOFFICENAME = TBL_USER_JOBMASTER.COMPANYID AND TBL_USERMASTER.TENANT_ID = TBL_USER_JOBMASTER.TENANT_ID WHERE TBL_USER_JOBMASTER.TYPE = #v_TYPE# AND TBL_USERMASTER.EXTENSIONATTRIBUTE7 = #v_JOBID# AND TBL_USERMASTER.PHYSICALDELIVERYOFFICENAME = #v_COMPANYID# AND TBL_USERMASTER.TENANT_ID = #v_TENANTID# AND TBL_USERMASTER.CN NOT IN (SELECT CN FROM TBL_USERMASTER_RETIRE WHERE TENANT_ID = #v_TENANTID#)
USERTREEFLAG = 'Y' AND DEPTTREEFLAG = 'Y'
)+( SELECT COUNT(*) FROM TBL_USER_JOBMASTER JOIN TBL_ADDJOBMASTER ON TBL_USER_JOBMASTER.JOBID = TBL_ADDJOBMASTER.JOBID AND TBL_USER_JOBMASTER.TENANT_ID = TBL_ADDJOBMASTER.TENANT_ID JOIN TBL_USERMASTER ON TBL_USERMASTER.CN = TBL_ADDJOBMASTER.CN AND TBL_USERMASTER.TENANT_ID = TBL_ADDJOBMASTER.TENANT_ID JOIN TBL_DEPTMASTER ON TBL_DEPTMASTER.CN = TBL_ADDJOBMASTER.DEPTID AND TBL_DEPTMASTER.TENANT_ID = TBL_USERMASTER.TENANT_ID WHERE TBL_USER_JOBMASTER.JOBID = #v_JOBID# AND TBL_USER_JOBMASTER.TENANT_ID = #v_TENANTID#
TBL_ADDJOBMASTER.USERTREEFLAG = 'Y' AND DEPTTREEFLAG = 'Y'
) AS COUNT FROM DUAL

SELECT( SELECT COUNT(*) FROM TBL_USERMASTER JOIN TBL_DEPTMASTER ON TBL_DEPTMASTER.CN = TBL_USERMASTER.DEPARTMENT AND TBL_DEPTMASTER.TENANT_ID = TBL_USERMASTER.TENANT_ID JOIN TBL_USER_JOBMASTER ON TBL_USERMASTER.EXTENSIONATTRIBUTE8 = TBL_USER_JOBMASTER.JOBID AND TBL_USERMASTER.PHYSICALDELIVERYOFFICENAME = TBL_USER_JOBMASTER.COMPANYID AND TBL_USERMASTER.TENANT_ID = TBL_USER_JOBMASTER.TENANT_ID WHERE TBL_USER_JOBMASTER.TYPE = #v_TYPE# AND TBL_USERMASTER.EXTENSIONATTRIBUTE8 = #v_JOBID# AND TBL_USERMASTER.PHYSICALDELIVERYOFFICENAME = #v_COMPANYID# AND TBL_USERMASTER.TENANT_ID = #v_TENANTID# AND TBL_USERMASTER.CN NOT IN (SELECT CN FROM TBL_USERMASTER_RETIRE WHERE TENANT_ID = #v_TENANTID#)
TBL_ADDJOBMASTER.USERTREEFLAG = 'Y' AND DEPTTREEFLAG = 'Y'
)+( SELECT COUNT(*) FROM TBL_USER_JOBMASTER JOIN TBL_ADDJOBMASTER ON TBL_USER_JOBMASTER.JOBID = TBL_ADDJOBMASTER.ROLEID AND TBL_USER_JOBMASTER.TENANT_ID = TBL_ADDJOBMASTER.TENANT_ID JOIN TBL_USERMASTER ON TBL_USERMASTER.CN = TBL_ADDJOBMASTER.CN AND TBL_USERMASTER.TENANT_ID = TBL_ADDJOBMASTER.TENANT_ID JOIN TBL_DEPTMASTER ON TBL_DEPTMASTER.CN = TBL_ADDJOBMASTER.DEPTID AND TBL_DEPTMASTER.TENANT_ID = TBL_USERMASTER.TENANT_ID WHERE TBL_USER_JOBMASTER.JOBID = #v_JOBID# AND TBL_USER_JOBMASTER.TENANT_ID = #v_TENANTID#
TBL_ADDJOBMASTER.USERTREEFLAG = 'Y' AND DEPTTREEFLAG = 'Y'
) AS COUNT FROM DUAL
